  1→import { publicGet, authedGet, authedJsonRequest, authedFormRequest } from "./apiHelpers";
  2→
  3→// ─── Auth / Profile ───
  4→
  5→export const checkUser = (userId) =>
  6→    publicGet(`/check-user?userId=${userId}`, 'failed to get user data');
  7→
  8→export const submitProfileData = (body, token) =>
  9→    authedFormRequest(token, 'POST', '/upload-user-data', body, 'Failed to upload data');
 10→
 11→export const updateProfileData = (body, token) =>
 12→    authedFormRequest(token, 'POST', '/update-user-data', body, 'failed to update profile data');
 13→
 14→export const getUserByUsername = (username) =>
 15→    publicGet(`/user/${encodeURIComponent(username)}`, 'failed to fetch user by username');
 16→
 17→export const checkUsernameAvailability = (username) =>
 18→    publicGet(`/check-username/${encodeURIComponent(username)}`, 'failed to check username');
 19→
 20→export const updateUsername = (token, username) =>
 21→    authedJsonRequest(token, 'POST', '/update-username', { username }, 'failed to update username');
 22→
 23→export const getUserData = (userId) =>
 24→    publicGet(`/getUserData?userId=${userId}`, 'Failed to fetch user data');
 25→
 26→export const updateFontColor = (token, fontColor) =>
 27→    authedFormRequest(token, 'POST', '/updateFontColor', fontColor, 'failed to update font color');
 28→
 29→// ─── Journals ───
 30→
 31→export const saveJournalImage = (token, body) =>
 32→    authedFormRequest(token, 'POST', '/save-journal-image', body, 'error uploading journal images');
 33→
 34→export const saveJournal = (token, body) =>
 35→    authedFormRequest(token, 'POST', '/save-journal', body, 'failed to save journal');
 36→
 37→export const updateJournal = (token, body) =>
 38→    authedFormRequest(token, 'POST', '/update-journal', body, 'failed to update journal');
 39→
 40→export const deleteJournalImage = async (token, url) => {
 41→    const data = { filepath: [] };
 42→    if (url.length) {
 43→        url.forEach(element => {
 44→            data.filepath.push(element.split('/journal-images/').pop());
 45→        });
 46→    }
 47→    return authedJsonRequest(token, 'POST', '/delete-journal-images', data, 'failed to delete journal images');
 48→};
 49→
 50→export const getFollowingFeed = (token, cursor = null, limit = 5) => {
 51→    const path = cursor
 52→        ? `/journals/following?limit=${limit}&before=${cursor}`
 53→        : `/journals/following?limit=${limit}`;
 54→    return authedGet(token, path, 'Failed to fetch following feed');
 55→};
 56→
 57→export const getForYouFeed = (token, offset = 0, limit = 5) =>
 58→    authedGet(token, `/journals/for-you?limit=${limit}&offset=${offset}`, 'Failed to fetch for-you feed');
 59→
 60→export const getInterestSections = (token) =>
 61→    authedGet(token, '/explore/interests', 'Failed to fetch interest sections');
 62→
 63→export const getJournals = async (cursor = null, limit = 5, userId) => {
 64→    let path = cursor
 65→        ? `/journals?limit=${limit}&before=${cursor}`
 66→        : `/journals?limit=${limit}`;
 67→    if (userId) path += `&userId=${userId}`;
 68→    return publicGet(path, 'Failed to fetch journals');
 69→};
 70→
 71→export const getMonthlyHottestJournals = (userId, limit = 10) => {
 72→    const parsedLimit = Number(limit);
 73→    if (Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 10) {
 74→        throw new Error('limit should be an integer between 1 and 10');
 75→    }
 76→    let path = `/journals/hottest-monthly?limit=${parsedLimit}`;
 77→    if (userId) path += `&userId=${encodeURIComponent(userId)}`;
 78→    return publicGet(path, 'failed to fetch monthly hottest journals');
 79→};
 80→
 81→export const searchUsers = (query, limit = 10) => {
 82→    const q = typeof query === 'string' ? query.trim() : '';
 83→    if (!q) return Promise.resolve({ data: [], hasMore: false });
 84→    return publicGet(`/users/search?query=${encodeURIComponent(q)}&limit=${limit}`, 'failed to search users');
 85→};
 86→
 87→export const searchFollowingUsers = (token, query = '', limit = 10) => {
 88→    const params = new URLSearchParams({ limit: String(limit) });
 89→    if (query) params.set('query', query);
 90→    return authedGet(token, `/users/following/search?${params}`, 'failed to search following users');
 91→};
 92→
 93→export const searchJournals = (query, limit = 10, userId) => {
 94→    const q = typeof query === 'string' ? query.trim() : '';
 95→    if (!q) return Promise.resolve({ data: [], hasMore: false, mode: 'keyword' });
 96→    let path = `/journals/search?query=${encodeURIComponent(q)}&limit=${limit}`;
 97→    if (userId) path += `&userId=${encodeURIComponent(userId)}`;
 98→    return publicGet(path, 'failed to search journals');
 99→};
100→
101→export const getJournalById = (journalId, userId, options = {}) => {
102→    if (!journalId) throw new Error('journalId is required');
103→    const params = new URLSearchParams();
104→    if (userId) params.set('userId', String(userId));
105→    if (options.includeRepostContent) params.set('includeRepostContent', 'true');
106→    const qs = params.toString();
107→    const path = qs
108→        ? `/journal/${encodeURIComponent(journalId)}?${qs}`
109→        : `/journal/${encodeURIComponent(journalId)}`;
110→    return publicGet(path, 'failed to fetch journal');
111→};
112→
113→export const getJournalContent = (journalId) => {
114→    if (!journalId) throw new Error('journalId is required');
115→    return publicGet(`/journal/${encodeURIComponent(journalId)}/content`, 'failed to fetch journal content');
116→};
117→
118→export const getUserJournals = (cursor = null, limit = 5, userId, token) => {
119→    const path = cursor
120→        ? `/userJournals?limit=${limit}&before=${cursor}&userId=${userId}`
121→        : `/userJournals?limit=${limit}&userId=${userId}`;
122→    return authedGet(token, path, 'failed to get response');
123→};
124→
125→export const getProfileMedia = (token, cursor = null, limit = 5) => {
126→    const params = new URLSearchParams({ limit: String(limit) });
127→    if (cursor) params.set('cursor', cursor);
128→    return authedGet(token, `/profileMedia?${params}`, 'failed to fetch profile media');
129→};
130→
131→export const getVisitedProfileMedia = (token, userId, cursor = null, limit = 5) => {
132→    if (!userId) throw new Error('userId is required');
133→    const params = new URLSearchParams({ userId: String(userId), limit: String(limit) });
134→    if (cursor) params.set('cursor', cursor);
135→    return authedGet(token, `/visitedProfileMedia?${params}`, 'failed to fetch visited profile media');
136→};
137→
138→export const deleteProfileMediaImage = (token, payload) =>
139→    authedJsonRequest(token, 'DELETE', '/media/image', payload || {}, 'failed to delete profile media image');
140→
141→export const getVisitedUserJournals = (cursor = null, limit = 5, userId, loggedInUserId) => {
142→    const path = cursor
143→        ? `/visitedUserJournals?limit=${limit}&before=${cursor}&userId=${userId}&loggedInUserId=${loggedInUserId}`
144→        : `/visitedUserJournals?limit=${limit}&userId=${userId}&loggedInUserId=${loggedInUserId}`;
145→    return publicGet(path, 'failed to get response');
146→};
147→
148→export const deleteJournal = (journalId, token) =>
149→    authedFormRequest(token, 'DELETE', `/deleteJournal/${journalId}`, undefined, 'failed to delete journal');
150→
151→// ─── Interactions ───
152→
153→export const clickLike = (token, body) =>
154→    authedJsonRequest(token, 'POST', '/like', body, 'error adding like');
155→
156→export const addComment = (token, body) =>
157→    authedJsonRequest(token, 'POST', '/addComment', body, 'failed to add comment');
158→
159→export const getComments = (cursor = null, limit = 10, postId) => {
160→    const path = cursor
161→        ? `/getComments?postId=${postId}&limit=${limit}&before=${cursor}`
162→        : `/getComments?postId=${postId}&limit=${limit}`;
163→    return publicGet(path, 'failed to fetch comments');
164→};
165→
166→export const updateRepostCaption = (token, { journalId, caption }) =>
167→    authedJsonRequest(token, 'POST', '/update-repost-caption', { journalId, caption }, 'failed to update repost caption');
168→
169→export const createRepost = (token, { sourceJournalId, caption }) =>
170→    authedJsonRequest(token, 'POST', '/repost', { sourceJournalId, caption }, 'failed to create repost');
171→
172→export const addBookmark = (token, journalId) =>
173→    authedJsonRequest(token, 'POST', '/addBookmark', journalId, 'error adding bookmark');
174→
