492→export const getJournalsService = async(limit, userId, before) => {
493→    if(isNaN(limit) || limit > 20 || limit < 1){
494→        console.error('limit should be integer, not below 1 and higher than 20');
495→        throw {status: 400, error: 'limit should be integer, not below 1 and higher than 20'};
496→    }
497→
498→    const parsedLimit = parseInt(limit);
499→
500→    let query = supabase
501→    .from('journals')
502→    .select(JOURNAL_METADATA_WITH_COUNTS_SELECT)
503→    .eq('privacy', 'public')
504→    .order('created_at', {ascending: false})
505→    .order('id', {ascending: false})
506→    .limit(parsedLimit + 1);
507→
508→    if(before){
509→        query = query.lt('created_at', before);
510→    }
511→
512→    const {data, error} = await query;
513→
514→    if(error){
515→        console.error('supabase error while fetching journals:', error.message);
516→        throw{status: 500, error: 'supabase error while fetching journals'}
517→    }
518→
519→    if(data.length === 0){
520→        const journalData = {
521→            data: [],
522→            hasMore: false
523→        }
524→        return journalData
525→    }
526→
527→    // If userId is provided, fetch personalization (likes/bookmarks/reactions)
528→    // Otherwise return journals with has_liked/has_bookmarked/user_reaction defaulting to false/null
529→    let userHasLikedSet = new Set();
530→    let userHasBookmarkedSet = new Set();
531→    let userReactionMap = new Map();
532→
533→    if(userId){
