279→.toolbar-color-trigger:hover {
280→    background-color: var(--bg-pill);
281→}
282→.toolbar-color-icon {
283→    font-weight: 700;
284→    font-size: 0.9rem;
285→    line-height: 1;
286→}
287→.toolbar-color-swatch {
288→    width: 16px;
289→    height: 4px;
290→    border-radius: 3px;
291→    border: 1px solid var(--editor-border);
292→}
293→.color-popover {
294→    position: absolute;
295→    top: calc(100% + 6px);
296→    left: 0;
297→    display: grid;
298→    grid-template-columns: repeat(6, 18px);
299→    gap: 6px;
300→    padding: 8px;
301→    background: var(--editor-bg);
302→    border: 1px solid var(--editor-border);
303→    border-radius: 8px;
304→    box-shadow: var(--shadow-modal);
305→    z-index: 12;
306→}
307→.color-swatch {
308→    width: 18px;
309→    height: 18px;
310→    border-radius: 4px;
311→    border: 1px solid var(--editor-border);
312→    cursor: pointer;
313→    background-color: transparent;
314→}
315→.color-swatch.is-default {
316→    background-image:
317→        linear-gradient(45deg, rgba(0, 0, 0, 0.15) 25%, transparent 25%),
318→        linear-gradient(-45deg, rgba(0, 0, 0, 0.15) 25%, transparent 25%),
319→        linear-gradient(45deg, transparent 75%, rgba(0, 0, 0, 0.15) 75%),
320→        linear-gradient(-45deg, transparent 75%, rgba(0, 0, 0, 0.15) 75%);
321→    background-size: 6px 6px;
322→    background-position: 0 0, 0 3px, 3px -3px, -3px 0px;
323→}
324→.color-swatch.is-selected {
325→    outline: 2px solid var(--editor-accent);
326→    outline-offset: 1px;
327→}
328→
329→/* ── Editor shell (flex-grow, scrollable) ── */
330→.editor-shell {
331→    position: relative;
332→    flex: 1;
333→    min-height: 0;
334→    overflow-y: auto;
335→    overflow-x: auto;
336→    scrollbar-width: thin;
337→    scrollbar-color: var(--text-muted) transparent;
338→}
339→.editor-shell::-webkit-scrollbar {
340→    width: 6px;
341→}
342→.editor-shell::-webkit-scrollbar-thumb {
343→    background: var(--text-muted);
344→    border-radius: 4px;
345→}
346→.editor-shell::-webkit-scrollbar-track {
347→    background-color: transparent;
348→}
349→
350→/* ── Editor content area ── */
351→.editor-text-container {
352→    white-space: pre-wrap;
353→    color: var(--editor-text);
354→    padding: 1rem 0.5rem;
355→}
356→.editor-input {
357→    font-synthesis: style;
358→}
359→.editor-input:focus {
360→    outline: none;
361→}
362→.editor-placeholder {
363→    color: var(--text-muted);
364→    overflow: hidden;
365→    position: absolute;
366→    top: -4px;
367→    user-select: none;
368→    pointer-events: none;
369→    margin: 0;
370→}
371→.editor-paragraph {
372→    margin: 0;
373→}
374→.editor-heading-h1 {
375→    margin: 0.9rem 0 0.45rem;
376→    font-size: 1.75rem;
377→    font-weight: 700;
378→    line-height: 1.25;
379→    color: var(--text-heading);
380→}
381→.editor-heading-h2 {
382→    margin: 0.8rem 0 0.4rem;
383→    font-size: 1.4rem;
384→    font-weight: 650;
385→    line-height: 1.3;
386→    color: var(--text-heading);
387→}
388→.editor-heading-h3 {
389→    margin: 0.7rem 0 0.35rem;
390→    font-size: 1.15rem;
391→    font-weight: 600;
392→    line-height: 1.35;
393→    color: var(--text-heading);
394→}
395→.editor-quote {
396→    margin: 0.5rem 0;
397→    padding: 0.3rem 0.65rem;
398→    border-left: 2px solid var(--editor-accent);
399→    background: color-mix(in srgb, var(--editor-accent) 5%, transparent);
400→    color: var(--editor-text);
401→    font-style: italic;
402→}
403→
404→/* ── Footer bar (word count + save) ── */
405→.editor-footer {
406→    display: flex;
407→    justify-content: space-between;
408→    align-items: center;
409→    padding: 0.5rem 0;
410→    border-top: 1px solid var(--editor-border);
411→    margin-top: auto;
412→}
413→.editor-word-count {
414→    font-size: 0.8rem;
415→    color: var(--text-muted);
416→    user-select: none;
417→    padding-left: 0.25rem;
418→}
419→
420→/* ── Bar loader positioning ── */
421→.editor-loader-wrapper {
422→    height: 4px;
423→    flex-shrink: 0;
424→}
425→
426→/* ── Save button ── */
427→.editor-save-bttn {
428→    display: flex;
429→    justify-content: center;
430→    align-items: center;
431→    padding: 0.5rem 1.25rem;
432→    border-radius: 15px;
433→    background-color: var(--editor-accent);
434→    color: #ffffff;
435→    font-weight: 650;
436→    cursor: pointer;
437→    border: none;
438→    transition: background-color 0.15s ease, transform 0.1s ease, opacity 0.15s ease;
439→}
440→.editor-save-bttn:hover {
441→    opacity: 0.9;
442→}
443→.editor-save-bttn:active {
444→    transform: scale(0.98);
445→}
446→.editor-save-bttn:focus {
447→    outline: none;
448→}
449→.editor-save-bttn-disabled {
450→    display: flex;
451→    justify-content: center;
452→    align-items: center;
453→    padding: 0.5rem 1.25rem;
454→    border-radius: 15px;
455→    background-color: var(--bg-pill);
456→    color: var(--text-muted);
457→    font-weight: 650;
458→    user-select: none;
459→    border: none;
460→    cursor: not-allowed;
461→}
462→.editor-save-bttn-disabled:focus {
463→    outline: none;
464→}
465→
466→/* ── Image upload icon (inside toolbar) ── */
467→.editor-upload-image-icon {
468→    padding: 0.4rem;
469→    border-radius: 6px;
470→    cursor: pointer;
471→    transition: all 0.15s ease;
472→}
473→.editor-upload-image-icon:hover {
474→    background-color: var(--bg-pill);
475→}
476→
477→/* ── Image components ── */
478→.image-container {
479→    display: flex;
480→    justify-content: center;
481→    width: 100%;
482→    height: fit-content;
483→}
484→.image-wrapper {
485→    position: relative;
486→    display: flex;
487→    justify-content: flex-end;
488→    margin: 1rem 0;
489→    width: fit-content;
490→    height: fit-content;
491→}
492→.image-actions {
493→    position: absolute;
494→    display: flex;
495→    gap: 0.3rem;
496→    top: 0;
497→    right: 0;
498→    margin: 0.5rem;
499→    z-index: 11;
500→}
501→.image-action-btn {
502→    display: flex;
503→    align-items: center;
504→    justify-content: center;
505→    padding: 0.4rem;
506→    border-radius: 50%;
507→    cursor: pointer;
508→    transition: ease-in-out 0.1s;
509→    background-color: rgba(0, 0, 0, 0.35);
510→}
511→.image-action-btn:hover {
512→    background-color: rgba(0, 0, 0, 0.55);
513→}
514→.dimension-display {
515→    position: absolute;
516→    display: flex;
517→    justify-content: center;
518→    align-items: center;
519→    top: -35px;
520→    left: 50%;
521→    transform: translateX(-50%);
522→    background-color: var(--bg-pill);
523→    color: var(--text-muted);
524→    padding: 0.4rem 0.5rem;
525→    white-space: nowrap;
526→    pointer-events: none;
527→    font-size: 0.8rem;
528→    border-radius: 4px;
529→}
530→
531→/* ── Resize handles ── */
532→.southeast-side-handle {
533→    position: absolute;
534→    bottom: -4px;
535→    right: -4px;
536→    width: 12px;
537→    height: 12px;
538→    background-color: var(--bg-pill);
539→    border: 1px solid var(--editor-text);
540→    border-radius: 50%;
541→    cursor: nwse-resize;
542→    z-index: 10;
543→}
544→.southwest-side-handle {
545→    position: absolute;
546→    bottom: -4px;
547→    left: -4px;
548→    width: 12px;
549→    height: 12px;
550→    background-color: var(--bg-pill);
551→    border: 1px solid var(--editor-text);
552→    border-radius: 50%;
553→    cursor: nesw-resize;
554→    z-index: 10;
555→}
556→.northeast-side-handle {
557→    position: absolute;
558→    top: -4px;
559→    right: -4px;
560→    width: 12px;
561→    height: 12px;
562→    background-color: var(--bg-pill);
563→    border: 1px solid var(--editor-text);
564→    border-radius: 50%;
565→    cursor: sw-resize;
566→    z-index: 10;
567→}
568→.northwest-side-handle {
569→    position: absolute;
570→    top: -4px;
571→    left: -4px;
572→    width: 12px;
573→    height: 12px;
574→    background-color: var(--bg-pill);
575→    border: 1px solid var(--editor-text);
576→    border-radius: 50%;
577→    cursor: se-resize;
578→    z-index: 10;
579→}
580→.east-side-handle {
581→    position: absolute;
582→    top: 50%;
583→    right: -4px;
584→    width: 8px;
585→    height: 20px;
586→    background-color: var(--bg-pill);
587→    border: 1px solid var(--editor-text);
588→    border-radius: 2px;
589→    transform: translateY(-50%);
590→    cursor: ew-resize;
591→    z-index: 10;
592→}
593→.south-side-handle {
594→    position: absolute;
595→    bottom: -4px;
596→    left: 50%;
597→    width: 20px;
598→    height: 8px;
599→    background-color: var(--bg-pill);
600→    border: 1px solid var(--editor-text);
601→    border-radius: 2px;
602→    transform: translateX(-50%);
603→    cursor: ns-resize;
604→    z-index: 10;
605→}
606→.north-side-handle {
607→    position: absolute;
608→    top: -4px;
609→    left: 50%;
610→    width: 20px;
611→    height: 8px;
612→    background-color: var(--bg-pill);
613→    border: 1px solid var(--editor-text);
614→    border-radius: 2px;
615→    transform: translateX(-50%);
616→    cursor: nw-resize;
617→    z-index: 10;
618→}
619→
620→/* ── Image loading overlay ── */
621→.image-loading-overlay {
622→    position: absolute;
623→    top: 0;
624→    left: 0;
625→    width: 100%;
626→    height: 100%;
627→    display: flex;
628→    flex-direction: column;
629→    justify-content: center;
630→    align-items: center;
631→    background-color: rgba(0, 0, 0, 0.45);
632→    border-radius: 5px;
633→    gap: 8px;
634→    pointer-events: none;
635→}
636→.image-loading-spinner {
637→    width: 28px;
638→    height: 28px;
639→    border: 3px solid rgba(255, 255, 255, 0.2);
640→    border-top: 3px solid var(--editor-accent);
641→    border-radius: 50%;
642→    animation: image-spin 0.8s linear infinite;
643→}
644→@keyframes image-spin {
645→    0% { transform: rotate(0deg); }
646→    100% { transform: rotate(360deg); }
647→}
648→
649→/* ── Full-screen image view ── */
650→.image-view {
651→    position: fixed;
652→    top: 0;
653→    left: 0;
654→    width: 100vw;
655→    height: 100vh;
656→    object-fit: contain;
657→    background: rgba(0, 0, 0, 0.7);
658→    z-index: 9999;
659→    cursor: zoom-out;
660→    box-sizing: border-box;
661→}
662→
663→/* ── Mobile responsive (overrides only) ── */
664→@media (max-width: 640px) {
665→    .editor-parent-container {
666→        z-index: 132;
667→    }
668→    .editor-container {
669→        width: 95%;
670→        height: 95%;
671→        padding: 0.75rem;
672→        border-radius: 12px;
673→    }
674→    .toolbar {
675→        justify-content: center;
676→    }
677→    .toolbar-bttns,
678→    .is-active {
679→        padding: 0.35rem;
680→    }
681→    .toolbar-bttns svg,
682→    .is-active svg {
683→        width: 18px;
684→        height: 18px;
685→    }
686→    .toolbar-divider {
687→        margin: 0 4px;
688→        height: 16px;
689→    }
